import{_ as t,o as i,c as n,ag as a}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt2404.jpg",l="/images/lekt2401.jpg",o="/images/lekt2402.jpg",s="/images/lekt2403.jpg",d="/images/lekt2405.jpg",u="/images/lekt2406.jpg",p="/images/lekt2407.jpg",h="/images/lekt2408.jpg",m="/images/lekt2411.jpg",c="/images/lekt2409.jpg",b="/images/lekt2410.jpg",_=JSON.parse('{"title":"Lektion 24","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion24.md","filePath":"lektionen/lektion24.md"}'),g={name:"lektionen/lektion24.md"};function k(f,e,v,q,w,D){return i(),n("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-24" tabindex="-1">Lektion 24 <a class="header-anchor" href="#lektion-24" aria-label="Permalink to &quot;Lektion 24&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>24.1. Der Dativ (चतुर्थी = &quot;vierte Kasusendung&quot;)</li><li>24.2. Bildung des Dativ (चतुर्थी) <ul><li>24.2.1. Konsonantische Stämme</li><li>24.2.2. Fragepronomen</li><li>24.2.3. Demonstrativpronomina</li><li>24.2.4. Vokalische Stämme</li></ul></li><li>24.3. Sandhi von auslautendem -ai und -au</li><li>24.4. Wortliste</li><li>24.5. Übung</li><li>24.6. Weitere Übungen zum Gebrauch des Dativ</li></ul><h2 id="_24-1-der-dativ-चतुर्थी-vierte-kasusendung" tabindex="-1">24.1. Der Dativ (चतुर्थी = &quot;vierte Kasusendung&quot;) <a class="header-anchor" href="#_24-1-der-dativ-चतुर्थी-vierte-kasusendung" aria-label="Permalink to &quot;24.1. Der Dativ (चतुर्थी = &quot;vierte Kasusendung&quot;)&quot;">​</a></h2><p>1. Um den Zweck oder eine Absicht (&quot;um zu&quot;) einer handlung wiederzugeben, kann man statt des Infinitivs (तुमुन्) auch ein Nomen mit kṛt-Suffix, das eine Handlung oder einen Zustand bezeichnet, im Dativ (चतुर्थी = &quot;vierte Kasusendung&quot;) verwenden.</p><p>Beispiel:</p><p>anstatt:</p><blockquote><p>रामो गुरुव्चनं श्रोतुं गतः ।</p></blockquote><p>kann man auch sagen:</p><blockquote><p>रामो गुरुवचनस्य श्रवणाय गतः ।</p></blockquote><p>oder:</p><blockquote><p>रामो गुरुवचनश्रवणाय गतः ।</p></blockquote><p>= &quot;Rāma ist gegangen, um die Rede des Lehrers zu hören.&quot;</p><p><img src="'+r+'" alt=""><br> Abb.: बाला गुरुश्रवणाय गताः<br> [Bildquelle: sknaB nolA. -- <a href="http://www.flickr.com/photos/nolasknab/110920752/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/nolasknab/110920752/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p><p>2. Der Dativ (चतुर्थी) kann auch das Objekt eines zu ergänzenden Infinitivs des Zweckes bezeichnen:</p><p>Beispiel:</p><blockquote><p>फलेभ्यो ग्रामं गच्छति = &quot;Er geht zum Zweck von Früchten ins Dorf = Er geht ins Dorf, um Früchte zu holen.&quot;</p></blockquote><p>In gleicher weise bezeichnet der Dativ (चतुर्थी) den Zweck eines Dinges oder einer Handlung:</p><p>Beispiel:</p><blockquote><p>यज्ञायान्नम् = &quot;Speise zum Zweck eines Opfers = Speise für ein Opfer&quot;</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: यज्ञायान्नम</p><blockquote><p>&quot;&#39;Annakut&#39; [अन्नकूट = गोवर्धन पूजा] is a traditional Hindu event that takes place on the Hindu New Year celebrations at all BAPS [બોચાસનવાસી અક્ષ૨ પુરુષોત્તમ સ્વામિનારાયણ સંસ્થા = Bochasanwasi Akshar Purushottam Swaminarayan Sanstha] mandirs. Hundreds of vegetarian dishes are offered to Bhagwan Swaminarayan [સ્વામિનારાયણ] on this day. All these dishes are made to offer devotion towards GOD. They are nicely decorated and placed on a decorated display set up.&quot;</p><p>[Bildquelle: chiragkpatel. -- <a href="http://www.flickr.com/photos/chiragkpatel/61224686/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/chiragkpatel/61224686/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p></blockquote><p>3. Der Dativ (चतुर्थी) bezeichnet auch die Person oder Sache, für die das Objekt einer Handlung bestimmt ist (indirektes Objekt ; Frage: wem?). (Beachten Sie aber die Verben mit doppeltem Akkusativ (द्वितीया)!)</p><p>Beispiel:</p><blockquote><p>रामाय फलं ददाति = &quot;Er gibt dem Rāma eine Frucht.&quot; (Wurzel दा 3. Präsensklasse)</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: बाला बलाय रक्षबन्धनं ददाति</p><blockquote><p>&quot;Raksha bandhan is celebrated with fervour and joy all across India. This festival epitomizes the unconditional love between brothers and sisters. The festival is marked by the tying of a rakhi, or holy thread by the sister on the wrist of her brother. The brother in return offers a gift to his sister and vows to look after her. The brother and sister traditionally feed each other sweets.&quot;</p><p>[Bildquelle: yogu. -- <a href="http://www.flickr.com/photos/meethi/1266237363/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/meethi/1266237363/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p></blockquote><p>4. Der Dativ steht bei einigen Verben (und einigen anderen Wörtern) ähnlich wie im Deutschen auf die Frage &quot;wem?&quot;:</p><p>Beispiele:</p><blockquote><p>क्रुध् : देवो नरेभ्यो क्रुध्यति = &quot;Der Gott zürnt den Männern.&quot;</p><p>अलम् Adverb: &quot;genug, hinreichend, gewachsen&quot;: अलं योधो योधाय = &quot;ein Krieger ist dem anderen Krieger gewachsen&quot;</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: अलं योधो योधाय<br> &quot;Rama (right) seated on the shoulders of Hanuman, battles the demon-king Ravana.&quot;<br> ca 1820<br> [Bildquelle: Wikipedia, Public domain]</p><p>Weitere Verwendungen des Dativ später.</p><h2 id="_24-2-bildung-des-dativ-चतुर्थी" tabindex="-1">24.2. Bildung des Dativ (चतुर्थी) <a class="header-anchor" href="#_24-2-bildung-des-dativ-चतुर्थी" aria-label="Permalink to &quot;24.2. Bildung des Dativ (चतुर्थी)&quot;">​</a></h2><p>Die regelmäßigen Endungen des Dativ sind:</p><blockquote><ul><li>Singular: -e ; vokalisch endende Femininstämme: -ai</li><li>Plural: Dativ und Ablativ (पञ्चमी): -bhyas</li></ul></blockquote><h3 id="_24-2-1-konsonantische-stamme" tabindex="-1">24.2.1. Konsonantische Stämme <a class="header-anchor" href="#_24-2-1-konsonantische-stamme" aria-label="Permalink to &quot;24.2.1. Konsonantische Stämme&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Dativ Singular</th><th>Dativ Plural</th></tr></thead><tbody><tr><td>यजन्त्</td><td>यजते</td><td></td></tr><tr><td>yaja-t-e</td><td>यजद्भ्यस्</td><td></td></tr><tr><td>aus yaja-t-bhyas</td><td></td><td></td></tr><tr><td>महान्त्</td><td>मह्ते</td><td>महद्भ्यस्</td></tr><tr><td>पशुमन्त्</td><td>पशुमते</td><td>पशुमद्भ्यस्</td></tr><tr><td>गुणवन्त्</td><td>गुणवते</td><td>गुणवद्भ्यस्</td></tr></tbody></table><h3 id="_24-2-2-fragepronomen" tabindex="-1">24.2.2. Fragepronomen <a class="header-anchor" href="#_24-2-2-fragepronomen" aria-label="Permalink to &quot;24.2.2. Fragepronomen&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Maskulinum / Neutrum</th><th>Femininum</th></tr></thead><tbody><tr><td>Dativ Singular</td><td>कस्मै</td><td>कस्यै</td></tr><tr><td>Dativ Plural</td><td>केभ्यस्</td><td>काभ्यस्</td></tr></tbody></table><h3 id="_24-2-3-demonstrativpronomina" tabindex="-1">24.2.3. Demonstrativpronomina <a class="header-anchor" href="#_24-2-3-demonstrativpronomina" aria-label="Permalink to &quot;24.2.3. Demonstrativpronomina&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th><th>तद्</th><th>एतद्</th><th>इदम्</th></tr></thead><tbody><tr><td>Maskulinum / Neutrum</td><td>Dativ Singular</td><td>तस्मै</td><td>एतस्मै</td><td>अस्मै</td></tr><tr><td></td><td>Dativ Plural</td><td>तेभ्यस्</td><td>एतेभ्यस्</td><td>एभ्यस्</td></tr><tr><td>Femininum</td><td>Dativ Singular</td><td>तस्यै</td><td>एतस्यै</td><td>अस्यै</td></tr><tr><td></td><td>Dativ Plural</td><td>ताभ्यस्</td><td>एताभ्यस्</td><td>आभ्यस्</td></tr></tbody></table><h3 id="_24-2-4-vokalische-stamme" tabindex="-1">24.2.4. Vokalische Stämme <a class="header-anchor" href="#_24-2-4-vokalische-stamme" aria-label="Permalink to &quot;24.2.4. Vokalische Stämme&quot;">​</a></h3><p>Maskulina / Neutra auf -a: देव</p><ul><li>Dat. sg. देवाय</li><li>Dat. pl. देवेभ्यस्</li></ul><p>Maskulina auf -i: कवि</p><ul><li>Dat. sg. कवये</li><li>Dat. pl. कविभ्यस्</li></ul><p>Maskulina auf -u: पशु</p><ul><li>Dat. sg. पशवे</li><li>Dat. pl. पशुभ्यस्</li></ul><p>Feminina auf -ā: देवता</p><ul><li>Dat. sg. देवतायै</li><li>Dat. pl. देवताभ्यस्</li></ul><p>Feminina auf -ī: देवी</p><ul><li>Dat. sg. देव्यै</li><li>Dat. pl. देवीभ्यस्</li></ul><p>Feminina auf -i: श्रुति</p><ul><li>Dat. sg. श्रुतये oder श्रुत्यै (d.h. wie कवि oder wie देवी)</li><li>Dat. pl. श्रुतिभ्यस्</li></ul><p>Feminina auf -u: धेनु</p><ul><li>Dat. sg. धेनवे oder धेन्वै</li><li>Dat. pl. धेनुभ्यस्</li></ul><h2 id="_24-3-sandhi-von-auslautendem-ai-und-au" tabindex="-1">24.3. Sandhi von auslautendem -ai und -au <a class="header-anchor" href="#_24-3-sandhi-von-auslautendem-ai-und-au" aria-label="Permalink to &quot;24.3. Sandhi von auslautendem -ai und -au&quot;">​</a></h2><ul><li>-ai vor anlautendem Vokal wird in der Regel durch -ā ersetzt (seltener durch -āy wie im Wortinneren</li><li>-au vor Vokal wird in der Regel durch -āv ersetzt (seltener durch -ā)</li></ul><p>Beispiel:</p><blockquote><p>तस्मै + अग्नये » तस्मा अग्नये = &quot;diesem Feuer&quot;</p></blockquote><h2 id="_24-4-wortliste" tabindex="-1">24.4. Wortliste <a class="header-anchor" href="#_24-4-wortliste" aria-label="Permalink to &quot;24.4. Wortliste&quot;">​</a></h2><p>अलम् Adverb: genug, hinreichend, (jemandem, etwas) gewachsen ; mit Dativ: genug für, hinreichend für, dem gewachsen ; mit Instrumentalis: genug mit, lass ab von , z.B. अलं क्रोधेन = &quot;genug mit dem Zorn = lass ab vom Zorn!&quot;</p><p>In gleicher Weise wie अलम् mit Instrumentalis wird verwendet:</p><p>कृतम् : कृतं क्रोधेन = &quot;Es ist getan mit dem Zorn = lass ab vom Zorn!&quot;</p><p>अलम् + कृ 8U अलंकरोति : schmücken</p><blockquote><p>अलंकार m.: Schmuck, Schmuckmittel (in der Dichtung)</p><p><img src="'+d+'" alt=""><br> Abb.: अलंकारः<br> [Bildquelle: sarboo. -- <a href="http://www.flickr.com/photos/sarboo/320741523/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/sarboo/320741523/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><p>हेतु m.: Antribe, Veranslassung, Ursache, Grund ; हेतुना, हेतोस्, हेतवे mit Genetiv oder als Hinterglied eines Kompositums = &quot;um ... willen, wegen&quot;</p><p>प्रतिमा f.: Bildnis, Abbild</p><p><img src="'+u+'" alt=""><br> Abb.: देवीप्रतिमा<br> Hampi = ಹಂಪೆ, Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: thaths. -- <a href="http://www.flickr.com/photos/thaths/862012190/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/thaths/862012190/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>वृत् + प्र 1Ā प्रवअर्तते : erfolgen, geschehen, entstehen</p><p>Von वृत्:</p><blockquote><p>वृत्ति f.: Benehmen, Tätigkeit, Lebensweise</p><p>वृत्त n.: Benehmen</p></blockquote><p>अभि Präverb:  be-, nach - hin, zu - her, zu - hin, gegen, in - hinein, in Bezug auf, auf, über, an</p><p>नि Präverb: niederwärts, hinunter, hinein, rückwärts</p><p>आ Präposition / Postposition: vor Ablativ oder nach Akkusativ: bis hin, bis zu ; mit Ablativ: von her, von an, seit</p><p>अतस् Indeklinabile: von da, dann, deshalb, daher (Pronominalstamm a- &quot;dieser&quot; + Ablativsuffix -tas)</p><p>अध्यक्ष m.: Aufseher, Departementschef ; Augenzeuge</p><p>इन्द्रिय n.: Kraft, Sinnesorgan</p><p>ऊह m.: Überlegung, Argumentation</p><p>davon</p><blockquote><p>अपोह m.: Negierung (अप + ऊह)</p><p>ऊहापोह m.: Diskussion des Für und Wider</p><p><img src="'+p+'" alt=""><br> Abb.: ऊहापोहः</p><p>&quot;NEW DELHI/INDIA, 16NOV08 - Suhasini Haidar, Deputy Foreign Editor, CNN-IBN Network 18, India, moderates a panel discussion at the World Economic Forum&#39;s India Economic Summit 2008 in New Delhi, 16-18 November 2008.&quot;</p><p>[Bildquelle: World Economic Forum / Photo by Dana Smillie. --<a href="http://www.flickr.com/photos/worldeconomicforum/3040064901/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldeconomicforum/3040064901/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p></blockquote><p>औपकारिक 3 f.: -ई : nützlich</p><p>कुप्य n.: Walderzeugnis, Metall (nicht Edelmetall)</p><p>ख्या 2P ख्याति PPP ख्यात : sehen, sichtbar werden ; nennen, erklären, mitteilen</p><blockquote><p>ख्या + आ 2P आख्यात : erzählen</p><p>davon:</p><blockquote><p>आख्यान n.: Erzählung</p></blockquote><p><img src="'+h+'" alt=""><br> Abb.: आख्यानम्</p><p>&quot;San Francisco storyteller Jeff Byers shares a story with the residents of Chenneri, an Irula village. Storyteller Jeeva Raghunath translates into Tamil for the villagers. &quot;</p><p>[Bildquelle: ereneta. -- <a href="http://www.flickr.com/photos/tereneta/3062024840/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/tereneta/3062024840/</a>. -- Zugriff am 2008-12-14. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>ख्या + सम् 2P संख्याति : zusammenzählen, berechnen</p><p>davon:</p><blockquote><p>संख्य m.: Zählung, Aufzählung ; eines der sechs philosopphischen System (kurz: Basham, Wonder S. 326f.)</p></blockquote></blockquote><p>ग्रहण n.: Ergreifen</p><p>चौल n.: Zermonie (संस्कार) des Haarschneidens (im Alter von 3 Jahren)</p><p>तत्त्व n.: wahres Wesen, Wahrheit, Realität (तद् + त्व = Dies-heit)</p><p>स्वस्ति f.: Glück, Heil (Nominalbildung aus सु अस्ति = &quot;es ist gut&quot;)</p><p>नमस् n.: Verbeugung, Verehrung, Gruß (Deklination später). Begrüßungsformel: नमो नमः</p><p>davon:</p><blockquote><p>कृ + नमस् 8 नमस्करोमि : sich verbeugen, verehren, begrüßen</p></blockquote><p><img src="'+m+'" alt=""><br> Abb.: जयदेवकविर्विष्णुं नमस्करोति<br> Manuskript des गीतगोविन्द, 1730 n. Chr.<br> [Bildquelle: Wikipedia, Public domain]</p><p>स्वागत n.: Willkommen (aus su-ā-gata)</p><p>तृण n.: Grashalm</p><p>पुनर् Adverb: wiederum, wieder, zurück, aber</p><h2 id="_24-5-ubung" tabindex="-1">24.5. Übung <a class="header-anchor" href="#_24-5-ubung" aria-label="Permalink to &quot;24.5. Übung&quot;">​</a></h2><p>A) Bilden Sie den Dativ Singular und den Dativ/(Ablativ) Plural und geben Sie die Bedeutung des Nominalstamms an:</p><ol><li>श्रव</li><li>भवन</li><li>गति</li><li>ऋषि</li><li>सुख</li><li>गमन</li><li>जय</li><li>साधु</li><li>धेनु</li><li>शुद्रा</li><li>ब्राह्मणी</li><li>अग्नि</li><li>एतद् ३</li><li>सन्त्</li><li>बुद्धिमन्त्</li><li>यज्ञ</li><li>वचन</li><li>सत्यवन्त्</li><li>स्मृति</li><li>सर्ग</li><li>स्वर्ग</li><li>दर्शन</li><li>सृष्टि</li><li>अर्हन्त्</li><li>भक्ति</li><li>दोष</li><li>पूजा</li><li>दासी</li><li>गुरु</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>ब्राह्मणो देवप्रतिमादर्शनाय गर्भगृहं विशति ॥१॥</p><p>नरा धनलाभाय व्रतानि चरन्ति ॥२॥</p><p>गुरुर्धर्मोपदेशाय नगरं गतः ॥३॥</p><p>बाला अपि गुरुवचनश्रुत्यै नगरं गताः ॥४॥</p><p>देवप्रतिमायै गृहं गर्भगृहम् ॥५॥</p><p>स्वर्गेभ्यो नराः पुण्यं कर्तुमिच्छन्ति ॥६॥</p><p>मोक्षार्थं बुद्धगता बुद्ध्याप्तिमिच्छन्ति ॥७॥</p><p>देवास्तेभ्यो ऽकृतपुजाब्रामणेभ्यः क्रुध्यन्ति ॥८॥</p><p>मरणाय जना जायन्ते ॥९॥</p><p>C) Geben Sie die Sätze A) 1-4 in Sanskrit wieder, indem Sie statt der Dative Infinitive (तुमुन्) setzen. Beachten Sie, dass der Infinitiv den gleichen Kasus regiert wie das entsprechende Verb.</p><p>D) Ersetzen Sie in Satz A) 7 die Konstruktion mit -अर्थ durch einen gleichwertigen Dativ.</p><p>E) Ersetzen Sie in Satz A) 6 die Dativkonstruktion durch eine gleichwertige Konstruktion mit -अर्थ</p><h2 id="_24-6-weitere-ubungen-zum-gebrauch-des-dativ" tabindex="-1">24.6. Weitere Übungen zum Gebrauch des Dativ <a class="header-anchor" href="#_24-6-weitere-ubungen-zum-gebrauch-des-dativ" aria-label="Permalink to &quot;24.6. Weitere Übungen zum Gebrauch des Dativ&quot;">​</a></h2><p>Übersetzen Sie ins Sanskrit:</p><p>1. Die Göttin, der man nicht geopfert hat, zürnt den Menschen.</p><p>2. Er lässt die Kuh ins Dorf los.</p><p>3. Jetzt reichts = Genug mit der Geduld.</p><p>4. Das ist gut (हित, सुख) für einen Brahmanen.</p><p>5. Verehrung (नमस्)  sei Śiva! Verehrung sei Śrī Gaṇeśa!</p><p><img src="'+c+'" alt=""><br> Abb.: श्रीगणेशाय नमः<br> [Bildquelle: Redtigerxyz / Wikipedia, GNU FDLicense]</p><p>6. Auf Wiedersehen! (= Wohlergehen (स्वस्ति f.)  Ihnen!)</p><p>7. Diese Frucht reicht zum Essen.</p><p>8. Ein Kämpfer ist dem (anderen) Kämpfer gewachsen (शक्त).</p><p>9. Selbst Viṣṇu übertrifft (प्र-भू + Dat.) Śiva nicht.</p><p>10. Nachdem ich mich vor den drei Weisen (Akk.) verbeugt habe (नमस्कृ)... Er verbeugt sich vor Narasiṃha (Dat.)</p><blockquote><p>Erklärung:  मुनित्रयम् &quot;die Dreiheit der Weisen = die drei Weisen&quot; = die Grammatiker पाणिनि, कात्यायन, पतञ्जलि</p></blockquote><p><img src="'+b+'" alt=""><br> Abb.: नरो नरसिंहाय नमस्करोति<br> नरसिंह zerfleischt हिरण्यकशिपु, Blatt aus einem Manuskript des भगवतपुराण<br> [Bildquelle: Wikipedia, Public domain]</p><p>11. Willkommen (स्वागतम्)  Ihnen. Willkommen der Königin.</p><p>12. Ich wünsche Ihnen Wohlergehen (कुशल) = Wohlergehen Ihnen!</p><p>13. Er betrachtet ihn nicht als Grashalm.</p><p>14. Es reicht eine Frucht zum Essen und Wasser zum Trinken.</p><p>15. Auf Widersehen! (Neusanskrit: पुनर्दर्शनाय)</p>',133)])])}const S=t(g,[["render",k]]);export{_ as __pageData,S as default};
